const qwen = async (messages, model, opts = {}) => {
  const base = ($env.DASHSCOPE_BASE_URL || 'https://dashscope-intl.aliyuncs.com/compatible-mode/v1').replace(/\/$/, '');
  const res = await this.helpers.httpRequest({
    method: 'POST', url: base + '/chat/completions',
    headers: { Authorization: 'Bearer ' + ($env.DASHSCOPE_API_KEY || ''), 'Content-Type': 'application/json' },
    body: Object.assign({ model, temperature: 0, messages }, opts), json: true,
  });
  return res.choices?.[0]?.message?.content ?? '';
};
const esc = (s) => String(s).replace(/'/g, "''");
const rows = $input.all().map(i => i.json);
const list = rows.slice(0, 50).map(r => ({
  id: r.candidate_id, agent: r.agent_id, type: r.candidate_type,
  confidence: Number(r.confidence), payload: r.payload_json,
}));
const sys = 'You triage memory candidates for a GOVERNED review queue. For each candidate recommend approve, reject, or hold with a one-line reason. Recommendations only — a human applies them. Invent nothing. Respond ONLY as JSON {"recommendations":[{"id":<int>,"recommendation":"approve|reject|hold","reason":"..."}]}.';
const raw = await qwen(
  [{ role: 'system', content: sys }, { role: 'user', content: 'Candidates:\n' + JSON.stringify(list) }],
  ($env.QWEN_CHAT_MODEL || 'qwen-plus'), { response_format: { type: 'json_object' } });
let recs = []; try { recs = JSON.parse(raw).recommendations || []; } catch (e) { recs = []; }
const counts = recs.reduce((a, r) => { a[r.recommendation] = (a[r.recommendation] || 0) + 1; return a; }, {});
const md = ['# Review queue digest', `Pending candidates: ${rows.length}`, '']
  .concat(recs.map(r => `- [${r.recommendation}] #${r.id} — ${r.reason}`)).join('\n');
const metadata = JSON.stringify({ pending: rows.length, counts }).replace(/'/g, "''");
return [{ json: { digest_md: esc(md), metadata, recommendations: recs } }];
